import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  Box,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  IconButton,
  Stack,
  CircularProgress,
  MenuItem,
} from '@mui/material';
import AddIcon from '@mui/icons-material/Add';
import DeleteIcon from '@mui/icons-material/Delete';
import { API_URL } from '../utils/apiUrl';

export default function OutletProducts() {
  const [outletProducts, setOutletProducts] = useState([]);
  const [masterItems, setMasterItems] = useState([]);
  const [outlets, setOutlets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [open, setOpen] = useState(false);

  const [form, setForm] = useState({
    outlet_id: '',
    product_id: '',
    outlet_price: '',
    stock: 0,
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      // Ekshathe sob data ana hocche
      const [opRes, masterRes, outletRes] = await Promise.all([
        axios.get(`${API_URL}/api/outlet-products`),
        axios.get(`${API_URL}/api/products`),
        axios.get(`${API_URL}/api/outlets`), // Apnar backend e outlet list thakte hobe
      ]);
      setOutletProducts(opRes.data.data || []);
      setMasterItems(masterRes.data.data || []);
      setOutlets(outletRes.data.data || []);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Backend-er schema onujayi number-e convert kora hochhe
    const payload = {
      product_id: Number(form.product_id),
      outlet_id: Number(form.outlet_id),
      price: Number(form.outlet_price), // Schema-te 'price' ache
      stock_quantity: Number(form.stock), // Schema-te 'stock_quantity'
      min_stock_level: 5, // Default ba form theke nite paren
      //   created_by: Number(user?.id || 1), // AuthContext theke user id nite hobe
      created_by: 1,
    };

    try {
      await axios.post(`${API_URL}/api/outlet-products`, payload);
      alert('Product Assigned Successfully!');
      setOpen(false);
      fetchData();
    } catch (error) {
      console.log(error.response?.data);
      alert(error.response?.data?.message || 'Validation failed');
    }
  };

  const handleDelete = async (id) => {
    // User theke confirmation newa
    if (
      window.confirm(
        'Are you sure you want to remove this product from the outlet?'
      )
    ) {
      try {
        // Backend e delete request pathano
        // Note: API_URL er sathe '/api/outlet-products' thik ache kina check korben
        await axios.delete(`${API_URL}/api/outlet-products/${id}`);

        alert('Product removed from outlet successfully!');

        // Table refresh korar jonno data abar fetch kora
        fetchData();
      } catch (error) {
        console.error('Error deleting outlet product:', error);
        alert(error.response?.data?.message || 'Failed to delete product');
      }
    }
  };

  return (
    <Box sx={{ padding: '24px' }}>
      <Stack direction="row" justifyContent="space-between" mb={3}>
        <Typography variant="h4" fontWeight="bold">
          Outlet Products & Inventory
        </Typography>
        <Button
          variant="contained"
          startIcon={<AddIcon />}
          onClick={() => setOpen(true)}
        >
          Assign to Outlet
        </Button>
      </Stack>

      <Card variant="outlined">
        <CardContent>
          {loading ? (
            <CircularProgress />
          ) : (
            <Table>
              <TableHead sx={{ backgroundColor: '#f5f5f5' }}>
                <TableRow>
                  <TableCell>Outlet</TableCell>
                  <TableCell>Product</TableCell>
                  <TableCell>Override Price</TableCell>
                  <TableCell>Current Stock</TableCell>
                  <TableCell align="right">Actions</TableCell>
                </TableRow>
              </TableHead>
              {/* <TableBody>
                {outletProducts.map((item) => (
                  <TableRow key={item.id}>
                    <TableCell>{item.outlet?.name}</TableCell>
                    <TableCell>
                      <b>{item.product?.name}</b>
                    </TableCell>
                    <TableCell>ŕ§ł{item.outlet_price}</TableCell>
                    <TableCell>
                      <Typography color={item.stock < 10 ? 'error' : 'inherit'}>
                        {item.stock}
                      </Typography>
                    </TableCell>
                    <TableCell align="right">
                      <IconButton color="error">
                        <DeleteIcon />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody> */}

              <TableBody>
                {outletProducts?.map((item) => (
                  <TableRow key={item.id}>
                    <TableCell>{item.outlet?.name}</TableCell>
                    <TableCell>
                      <b>{item.product?.name}</b>
                    </TableCell>

                    {/* price check: Prisma Decimal hole string-e convert hoye ashte pare */}
                    <TableCell>ŕ§ł{item.price || 0}</TableCell>

                    {/* stock_quantity check: Schema-te stock_quantity ache, shudu stock na */}
                    <TableCell>
                      <Typography
                        color={item.stock_quantity < 10 ? 'error' : 'inherit'}
                      >
                        {item.stock_quantity ?? 0}
                      </Typography>
                    </TableCell>

                    <TableCell align="right">
                      <IconButton
                        color="error"
                        // onClick={() => handleDelete(item.id)}
                      >
                        <DeleteIcon />
                      </IconButton>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      {/* Assignment Dialog */}
      <Dialog
        open={open}
        onClose={() => setOpen(false)}
        fullWidth
        maxWidth="xs"
      >
        <DialogTitle>Assign Master Item to Outlet</DialogTitle>
        <form onSubmit={handleSubmit}>
          <DialogContent>
            <Stack spacing={2}>
              <TextField
                select
                label="Select Outlet"
                fullWidth
                required
                value={form.outlet_id}
                onChange={(e) =>
                  setForm({ ...form, outlet_id: e.target.value })
                }
              >
                {outlets.map((o) => (
                  <MenuItem key={o.id} value={o.id}>
                    {o.name}
                  </MenuItem>
                ))}
              </TextField>

              <TextField
                select
                label="Select Master Product"
                fullWidth
                required
                value={form.product_id}
                onChange={(e) => {
                  const p = masterItems.find((x) => x.id === e.target.value);
                  setForm({
                    ...form,
                    product_id: e.target.value,
                    outlet_price: p?.base_price,
                  });
                }}
              >
                {masterItems.map((p) => (
                  <MenuItem key={p.id} value={p.id}>
                    {p.name}
                  </MenuItem>
                ))}
              </TextField>

              {/* <TextField
                label="Outlet Specific Price"
                type="number"
                fullWidth
                required
                value={form.outlet_price}
                onChange={(e) =>
                  setForm({ ...form, outlet_price: e.target.value })
                }
              />

              <TextField
                label="Initial Stock"
                type="number"
                fullWidth
                required
                value={form.stock}
                onChange={(e) => setForm({ ...form, stock: e.target.value })}
              /> */}

              <TextField
                label="Outlet Specific Price"
                type="number"
                fullWidth
                required
                value={form.outlet_price}
                // inputProps ensure korbe jate ekhane negative number na dewa jay
                inputProps={{ min: 0, step: '0.01' }}
                onChange={(e) =>
                  setForm({ ...form, outlet_price: e.target.value })
                }
              />

              <TextField
                label="Initial Stock"
                type="number"
                fullWidth
                required
                value={form.stock}
                inputProps={{ min: 0 }}
                onChange={(e) => setForm({ ...form, stock: e.target.value })}
              />
            </Stack>
          </DialogContent>
          <DialogActions sx={{ p: 3 }}>
            <Button onClick={() => setOpen(false)}>Cancel</Button>
            <Button type="submit" variant="contained">
              Confirm Assignment
            </Button>
          </DialogActions>
        </form>
      </Dialog>
    </Box>
  );
}
